package com.example.enterpriseapp.user;

import java.util.List;
import java.util.Optional;

import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class UserServiceImpl implements UserService {

    private final UserRepository userRepository;

    public UserServiceImpl(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Override
    public AppUser createUser(AppUser user) {
        if (userRepository.existsByUsername(user.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (userRepository.existsByEmail(user.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }
        return userRepository.save(user);
    }

    @Override
    public AppUser updateUser(Long id, AppUser user) {
        AppUser existing = userRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        existing.setUsername(user.getUsername());
        existing.setEmail(user.getEmail());
        existing.setFullName(user.getFullName());
        existing.setActive(user.isActive());
        return userRepository.save(existing);
    }

    @Override
    @Transactional(readOnly = true)
    public Optional<AppUser> getUserById(Long id) {
        return userRepository.findById(id);
    }

    @Override
    @Transactional(readOnly = true)
    public Optional<AppUser> getUserByUsername(String username) {
        return userRepository.findByUsername(username);
    }

    @Override
    @Transactional(readOnly = true)
    public List<AppUser> getAllUsers() {
        return userRepository.findAll();
    }

    @Override
    public void deactivateUser(Long id) {
        AppUser user = userRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setActive(false);
        userRepository.save(user);
    }

    @Override
    public void deleteUser(Long id) {
        if (!userRepository.existsById(id)) {
            throw new IllegalArgumentException("User not found");
        }
        userRepository.deleteById(id);
    }
}

package com.example.enterpriseapp.transaction;

import com.example.enterpriseapp.user.AppUser;
import com.example.enterpriseapp.user.UserRepository;
import java.math.BigDecimal;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class TransactionServiceImpl implements TransactionService {

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionServiceImpl(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Override
    public AppTransaction createTransaction(Long userId, String referenceNumber, BigDecimal amount, String currency) {
        AppUser user = userRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        String ref = referenceNumber == null || referenceNumber.isBlank() ? UUID.randomUUID().toString() : referenceNumber;
        AppTransaction transaction = new AppTransaction(ref, user, amount, currency, "PENDING");
        return transactionRepository.save(transaction);
    }

    @Override
    public AppTransaction updateTransactionStatus(Long transactionId, String status) {
        AppTransaction transaction = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        transaction.setStatus(status);
        return transactionRepository.save(transaction);
    }

    @Override
    @Transactional(readOnly = true)
    public Optional<AppTransaction> getTransactionById(Long id) {
        return transactionRepository.findById(id);
    }

    @Override
    @Transactional(readOnly = true)
    public Optional<AppTransaction> getTransactionByReferenceNumber(String referenceNumber) {
        return Optional.ofNullable(transactionRepository.findByReferenceNumber(referenceNumber));
    }

    @Override
    @Transactional(readOnly = true)
    public List<AppTransaction> getTransactionsByUserId(Long userId) {
        return transactionRepository.findByUserId(userId);
    }

    @Override
    @Transactional(readOnly = true)
    public List<AppTransaction> getTransactionsByStatus(String status) {
        return transactionRepository.findByStatus(status);
    }
}

package com.example.enterpriseapp.web;

import com.example.enterpriseapp.transaction.AppTransaction;
import com.example.enterpriseapp.transaction.TransactionService;
import com.example.enterpriseapp.user.AppUser;
import com.example.enterpriseapp.user.UserService;
import java.math.BigDecimal;
import java.util.List;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.ResponseStatus;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api")
public class EnterpriseController {

    private final UserService userService;
    private final TransactionService transactionService;

    public EnterpriseController(UserService userService, TransactionService transactionService) {
        this.userService = userService;
        this.transactionService = transactionService;
    }

    @PostMapping("/users")
    @ResponseStatus(HttpStatus.CREATED)
    public AppUser createUser(@RequestBody AppUser user) {
        return userService.createUser(user);
    }

    @GetMapping("/users")
    public List<AppUser> getUsers() {
        return userService.getAllUsers();
    }

    @GetMapping("/users/{id}")
    public AppUser getUser(@PathVariable Long id) {
        return userService.getUserById(id).orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    @PutMapping("/users/{id}")
    public AppUser updateUser(@PathVariable Long id, @RequestBody AppUser user) {
        return userService.updateUser(id, user);
    }

    @PostMapping("/transactions/{userId}")
    @ResponseStatus(HttpStatus.CREATED)
    public AppTransaction createTransaction(@PathVariable Long userId, @RequestBody TransactionRequest request) {
        return transactionService.createTransaction(userId, request.getReferenceNumber(), request.getAmount(), request.getCurrency());
    }

    @PutMapping("/transactions/{transactionId}/status")
    public AppTransaction updateTransactionStatus(@PathVariable Long transactionId, @RequestBody StatusRequest request) {
        return transactionService.updateTransactionStatus(transactionId, request.getStatus());
    }

    public static class TransactionRequest {
        private String referenceNumber;
        private BigDecimal amount;
        private String currency;

        public String getReferenceNumber() {
            return referenceNumber;
        }

        public void setReferenceNumber(String referenceNumber) {
            this.referenceNumber = referenceNumber;
        }

        public BigDecimal getAmount() {
            return amount;
        }

        public void setAmount(BigDecimal amount) {
            this.amount = amount;
        }

        public String getCurrency() {
            return currency;
        }

        public void setCurrency(String currency) {
            this.currency = currency;
        }
    }

    public static class StatusRequest {
        private String status;

        public String getStatus() {
            return status;
        }

        public void setStatus(String status) {
            this.status = status;
        }
    }
}

